def matriz_exportable_desde_bloques(bloques, movimientos_sel, mostrar_anio: bool) -> pd.DataFrame:
    registros = []
    for bloque in bloques:
        registros.append({
            "semana_origen": etiqueta_periodo(bloque["origen"], mostrar_anio),
            "nivel": "origen",
            "etapa_subetapa": f'Total cohorte: {bloque["total_cohorte"]:,} leads',
        })

        for pipeline in bloque["pipelines"]:
            r_pipe = {
                "semana_origen": "",
                "nivel": "etapa",
                "etapa_subetapa": pipeline["pipeline"],
            }
            for mov in movimientos_sel:
                label = etiqueta_periodo(mov, mostrar_anio)
                vals = pipeline["valores"].get(mov, {})
                r_pipe[f"{label} Leads"] = vals.get("leads", 0)
                r_pipe[f"{label} %"] = vals.get("pct_num", 0)
            registros.append(r_pipe)

            for sub in pipeline["subetapas"]:
                r_sub = {
                    "semana_origen": "",
                    "nivel": "subetapa",
                    "etapa_subetapa": sub["subetapa"],
                }
                for mov in movimientos_sel:
                    label = etiqueta_periodo(mov, mostrar_anio)
                    vals = sub["valores"].get(mov, {})
                    r_sub[f"{label} Leads"] = vals.get("leads", 0)
                    r_sub[f"{label} %"] = vals.get("pct_num", 0)
                registros.append(r_sub)

    return pd.DataFrame(registros)


def render_encabezado(ultima_actualizacion):
    fecha_txt = ultima_actualizacion.strftime("%d/%m/%Y %H:%M") if pd.notna(ultima_actualizacion) else "Sin dato"
    st.markdown(
        f"""
        <div class="top-banner">
            <div class="top-banner-left">
                <img src="data:image/png;base64,{LOGO_B64}" alt="Hoy Me Pensiono Bitrix24">
                <div>
                    <div class="top-title">Bitrix Cohortes Marketing</div>
                    <div class="top-subtitle">"Visión operativa del avance de oportunidades por semana de origen y etapa.".</div>
                </div>
            </div>
            <div class="top-updated">
                <div class="lbl">Última fecha de actualización</div>
                <div class="val">{fecha_txt}</div>
            </div>
        </div>
        """,
        unsafe_allow_html=True,
    )


def render_leyenda():
    st.markdown(
        """
        <div class="legend-card">
            <div class="legend-title">Semáforos</div>
            <div class="legend-grid">
                <div><strong>Porcentajes:</strong> 🟢 alto cumplimiento | 🟡 medio | 🔴 bajo.</div>
                <div><strong>Horas desde origen:</strong> 🟢 0 a 47 h | 🟡 48 a 71 h | 🟠 72 a 95 h | 🔴 96 h.</div>
            </div>
        </div>
        """,
        unsafe_allow_html=True,
    )


# =========================
# App
# =========================

aplicar_estilos_app()
df = cargar()
ultima_actualizacion = df["fecha_evento"].max() if not df.empty else pd.NaT
render_encabezado(ultima_actualizacion)
render_leyenda()

anios = sorted(df["anio_origen"].dropna().unique().astype(int))
anios_sel = st.sidebar.multiselect("Años origen", anios, default=anios)

df = df[df["anio_origen"].isin(anios_sel)].copy()
mostrar_anio = len(anios_sel) > 1

periodos_origen = ordenar_periodos(df["periodo_origen"].dropna().unique())
default_origen = periodos_origen[-4:] if len(periodos_origen) >= 4 else periodos_origen
origenes_sel = st.sidebar.multiselect(
    "Semanas origen",
    periodos_origen,
    default=default_origen,
    format_func=lambda p: etiqueta_periodo(p, mostrar_anio),
)

base = df[df["periodo_origen"].isin(origenes_sel)].copy()

periodos_movimiento = ordenar_periodos(base["periodo_movimiento"].dropna().unique())
if origenes_sel:
    min_origen = min(origenes_sel, key=key_periodo)
    default_movimiento = [p for p in periodos_movimiento if key_periodo(p) >= key_periodo(min_origen)]
else:
    default_movimiento = periodos_movimiento

movimientos_sel = st.sidebar.multiselect(
    "Semanas de movimiento / cambio de etapa",
    periodos_movimiento,
    default=default_movimiento,
    format_func=lambda p: etiqueta_periodo(p, mostrar_anio),
)

st.sidebar.markdown("---")
st.sidebar.subheader("Semáforo de porcentajes")
amarillo_desde = st.sidebar.number_input(
    "Amarillo desde (%)",
    min_value=0.0,
    max_value=100.0,
    value=5.0,
    step=0.5,
)
verde_desde = st.sidebar.number_input(
    "Verde desde (%)",
    min_value=0.0,
    max_value=100.0,
    value=20.0,
    step=0.5,
)

if verde_desde < amarillo_desde:
    st.sidebar.warning("El umbral verde debe ser mayor o igual al amarillo.")
    verde_desde = amarillo_desde

abrir_subetapas = st.sidebar.checkbox("Abrir subetapas por defecto", value=False)

if not origenes_sel or not movimientos_sel:
    st.warning("Selecciona al menos una semana origen y una semana de movimiento.")
    st.stop()

bloques = construir_bloques(base, origenes_sel, movimientos_sel)

st.subheader("Resumen cohortes")
st.caption("Una fila por semana origen. Las etapas se muestran como columnas, con conversión y semáforo adicional por horas desde origen.")

resumen_etapas, etapas_resumen_columnas = construir_resumen_etapas_columnas(
    base=base,
    origenes_sel=origenes_sel,
    movimientos_sel=movimientos_sel,
    mostrar_anio=mostrar_anio,
    amarillo_desde=amarillo_desde,
    verde_desde=verde_desde,
)

if resumen_etapas.empty:
    st.info("No hay información de etapas para los filtros seleccionados.")
else:
    formato_resumen = {
        "Leads": "{:,.0f}",
        "Ventas": "{:,.0f}",
        "% Conversión": "{:.1f}%",
        "Horas prom.": "{:.1f} h",
    }
    formato_resumen.update({etapa: "{:,.0f}" for etapa in etapas_resumen_columnas})

    resumen_styled = resumen_etapas.style.apply(
        lambda row: estilo_resumen_columnas(row, etapas_resumen_columnas, amarillo_desde, verde_desde),
        axis=1,
    ).format(formato_resumen)

    st.dataframe(resumen_styled, use_container_width=True, hide_index=True)

    st.download_button(
        "Descargar resumen cohortes CSV",
        data=resumen_etapas.to_csv(index=False, encoding="utf-8-sig"),
        file_name="resumen_cohortes_etapas_columnas.csv",
        mime="text/csv",
    )

st.subheader("Matriz etapa → subetapa por semana")
st.caption("Da clic en cada etapa para desplegar u ocultar sus subetapas.")

if not bloques:
    st.info("No hay información para los filtros seleccionados.")
else:
    st.markdown(
        renderizar_matriz_desplegable_html(
            bloques=bloques,
            movimientos_sel=movimientos_sel,
            mostrar_anio=mostrar_anio,
            amarillo_desde=amarillo_desde,
            verde_desde=verde_desde,
            abrir_subetapas=abrir_subetapas,
        ),
        unsafe_allow_html=True,
    )

    export = matriz_exportable_desde_bloques(bloques, movimientos_sel, mostrar_anio)
    st.download_button(
        "Descargar matriz CSV",
        data=export.to_csv(index=False, encoding="utf-8-sig"),
        file_name="matriz_etapas_subetapas_desplegable.csv",
        mime="text/csv",
    )

    with st.expander("Ver matriz en formato dataframe"):
        st.dataframe(export, use_container_width=True, hide_index=True)

st.markdown('<div class="footer-sign">By Karina Ruiz</div>', unsafe_allow_html=True)
